import { assert, assertEquals, assertRejects } from "#std/assert";
import { build } from "./mod.ts";
import { Project } from "@/src/discovery/domain/data/project/mod.ts";

Deno.test("build — happy path", async () => {
  const dir = await Deno.makeTempDir();
  try {
    const out = await build({ projectRoot: dir });
    assert(Array.isArray(out.entrys));
    assertEquals(out.entrys.length, 0);
    assert(Array.isArray(out.problems));
  } finally {
    await Deno.remove(dir, { recursive: true });
  }
});

Deno.test("scan-failed", async () => {
  await assertRejects(
    () =>
      new Project().scan("/x", {
        discover: () => {
          throw new Error("unreadable");
        },
      }),
    Error,
    "scan-failed",
  );
});
